class Solution:
    def strWithout3a3b(self, a: int, b: int) -> str:
        result = []
        while a > 0 and b > 0:
            if a > b:
                result.append('a')
                a -= 1
            else:
                result.append('b')
                b -= 1
        result.extend('a' * a + 'b' * b)
        return ''.join(result)

